    width = rng.randint(2, 12)
    height = rng.randint(2, 12)
    ops = ['Robot']
    args = [[width, height]]
    for _ in range(max(1, size)):
        ops.append('step'); args.append([rng.randint(1, 250)])
        if rng.random() < 0.7:
            ops.append('getPos'); args.append([])
        if rng.random() < 0.7:
            ops.append('getDir'); args.append([])
    return [ops, args]

