class Robot:
    DIRS = ['East', 'North', 'West', 'South']
    DX = {'East': 1, 'North': 0, 'West': -1, 'South': 0}
    DY = {'East': 0, 'North': 1, 'West': 0, 'South': -1}

    def __init__(self, width, height):
        self.w = width
        self.h = height
        self.x = 0
        self.y = 0
        self.dir_idx = 0

    def step(self, num):
        for _ in range(num):
            d = self.DIRS[self.dir_idx]
            nx, ny = self.x + self.DX[d], self.y + self.DY[d]
            if not (0 <= nx < self.w and 0 <= ny < self.h):
                self.dir_idx = (self.dir_idx + 1) % 4
                d = self.DIRS[self.dir_idx]
                nx, ny = self.x + self.DX[d], self.y + self.DY[d]
            self.x, self.y = nx, ny

    def getPos(self):
        return [self.x, self.y]

    def getDir(self):
        return self.DIRS[self.dir_idx]

