class Robot:
    def __init__(self, width, height):
        self.w = width
        self.h = height
        self.perimeter = 2 * (width + height - 2)
        self.total = 0

    def step(self, num):
        self.total += num

    def _state(self):
        w, h = self.w, self.h
        perim = self.perimeter
        eff = self.total % perim
        s = perim if (eff == 0 and self.total > 0) else eff
        seg1 = w - 1
        seg2 = seg1 + (h - 1)
        seg3 = seg2 + (w - 1)
        if s <= seg1:
            return (s, 0, 'East')
        if s <= seg2:
            return (w - 1, s - seg1, 'North')
        if s <= seg3:
            return (w - 1 - (s - seg2), h - 1, 'West')
        return (0, h - 1 - (s - seg3), 'South')

    def getPos(self):
        x, y, _ = self._state()
        return [x, y]

    def getDir(self):
        return self._state()[2]

