class Robot {
    constructor(width, height) {
        this.w = width;
        this.h = height;
        this.perimeter = 2 * (width + height - 2);
        this.total = 0;
    }

    step(num) {
        this.total += num;
    }

    _state() {
        const w = this.w, h = this.h, perim = this.perimeter;
        const eff = this.total % perim;
        const s = (eff === 0 && this.total > 0) ? perim : eff;
        const seg1 = w - 1;
        const seg2 = seg1 + (h - 1);
        const seg3 = seg2 + (w - 1);
        if (s <= seg1) return [s, 0, 'East'];
        if (s <= seg2) return [w - 1, s - seg1, 'North'];
        if (s <= seg3) return [w - 1 - (s - seg2), h - 1, 'West'];
        return [0, h - 1 - (s - seg3), 'South'];
    }

    getPos() {
        const [x, y] = this._state();
        return [x, y];
    }

    getDir() {
        return this._state()[2];
    }
}
